class Stack:
    def __init__(self):
        self.items = []
    def push(self, item):
        self.items.append(item)
    def pop(self):
        if not self.items:
            raise IndexError("Pop from empty stack")
        return self.items.pop()
    def is_empty(self):
        return len(self.items) == 0

tests.code:
def test_stack_is_empty_true():
    stack = Stack()
    assert stack.is_empty() is True
